  [4] label=2 diagnosis={'n': 512, 'mean': 0.0, 'std': 0.999, 'trend_slope': 0.0004, 'trend_tstat': 1.22, 'adf_pvalue': 0.001, 'acf_peak_lag': 2, 'acf_peak_value': 0.994, 'trend_conf': 'low', 'season_conf': 'low', 'stat_conf': 'high'}
